import { useEffect, useMemo, useState } from "react";
import { findMatchingWords, preprocessWordList } from "./lib/dictionary";
import {
  keepHebrewLetters,
  normalizeFinalLetters,
  restoreFinalLettersForDisplay,
} from "./lib/hebrew";
import {
  findMultiWordAnagrams,
  isRequiredWordSatisfiable,
  MULTI_WORD_DEFAULT_MAX_INPUT_LETTERS,
  MULTI_WORD_DEFAULT_MAX_RESULTS,
  MULTI_WORD_DEFAULT_MAX_WORDS,
  type MultiWordResult,
} from "./lib/multiwordAnagrams";
import { findWordsByPattern } from "./lib/patternSearch";
import { scoreWord } from "./lib/scoring";
import "./yuval.css";

const DICT_URL = `${import.meta.env.BASE_URL}hebrew_dict.txt`;

type Mode = "single" | "multi" | "crossword";
type SortOrder = "longest" | "shortest" | "dict";

interface Options {
  mode: Mode;
  minLength: number;
  maxWords: number;
  sort: SortOrder;
  normalizeFinals: boolean;
}

const DEFAULT_OPTIONS: Options = {
  mode: "multi",
  minLength: 2,
  maxWords: MULTI_WORD_DEFAULT_MAX_WORDS,
  sort: "longest",
  normalizeFinals: true,
};

type DictState =
  | { status: "loading" }
  | { status: "ready"; raw: string }
  | { status: "error" };

function norm(s: string): string {
  return normalizeFinalLetters(keepHebrewLetters(s));
}

// ── Main component ────────────────────────────────────────────────────────

export default function YuvalApp() {
  const [dict, setDict] = useState<DictState>({ status: "loading" });
  const [rack, setRack] = useState("");
  const [fixedWord, setFixedWord] = useState("");
  const [opts, setOpts] = useState<Options>(DEFAULT_OPTIONS);

  useEffect(() => {
    fetch(DICT_URL)
      .then((r) => r.text())
      .then((raw) => setDict({ status: "ready", raw }))
      .catch(() => setDict({ status: "error" }));
  }, []);

  const preprocessed = useMemo<string[] | null>(() => {
    if (dict.status !== "ready") return null;
    return preprocessWordList(dict.raw, {
      minLength: 2,
      normalizeFinals: opts.normalizeFinals,
    });
  }, [dict, opts.normalizeFinals]);

  const sanitizedRack =
    opts.mode === "crossword" ? rack.trim() : keepHebrewLetters(rack);
  const sanitizedFixed = keepHebrewLetters(fixedWord);

  const fixedWordValid = useMemo(() => {
    if (opts.mode !== "multi" || !sanitizedFixed || !sanitizedRack) return true;
    const r = opts.normalizeFinals ? norm(sanitizedRack) : sanitizedRack;
    const f = opts.normalizeFinals ? norm(sanitizedFixed) : sanitizedFixed;
    return isRequiredWordSatisfiable(f, r);
  }, [opts.mode, opts.normalizeFinals, sanitizedFixed, sanitizedRack]);

  type SearchResult =
    | { kind: "empty" }
    | { kind: "loading" }
    | { kind: "error" }
    | { kind: "too-long" }
    | { kind: "fixed-invalid" }
    | { kind: "single"; words: { word: string; score: number }[] }
    | { kind: "multi"; combos: MultiWordResult[] }
    | { kind: "crossword"; words: { word: string; score: number }[] };

  const result = useMemo<SearchResult>(() => {
    if (dict.status === "loading") return { kind: "loading" };
    if (dict.status === "error") return { kind: "error" };
    if (!preprocessed) return { kind: "empty" };

    if (opts.mode === "crossword") {
      if (!rack.trim()) return { kind: "empty" };
      const matched = findWordsByPattern(rack.trim(), preprocessed, {
        normalizeFinals: opts.normalizeFinals,
      });
      return {
        kind: "crossword",
        words: matched.map((w) => ({ word: restoreFinalLettersForDisplay(w), score: scoreWord(w) })),
      };
    }

    if (!sanitizedRack) return { kind: "empty" };

    if (opts.mode === "multi") {
      if (sanitizedRack.length > MULTI_WORD_DEFAULT_MAX_INPUT_LETTERS) return { kind: "too-long" };
      const effectiveRack = opts.normalizeFinals ? norm(sanitizedRack) : sanitizedRack;
      const effectiveFixed = sanitizedFixed
        ? opts.normalizeFinals ? norm(sanitizedFixed) : sanitizedFixed
        : "";
      if (effectiveFixed && !isRequiredWordSatisfiable(effectiveFixed, effectiveRack)) {
        return { kind: "fixed-invalid" };
      }
      const combos = findMultiWordAnagrams(effectiveRack, preprocessed, {
        requiredWord: effectiveFixed || undefined,
        maxWords: opts.maxWords,
        minLength: opts.minLength,
      });
      return { kind: "multi", combos };
    }

    // single mode
    const effectiveRack = opts.normalizeFinals ? norm(sanitizedRack) : sanitizedRack;
    const matched = findMatchingWords(effectiveRack, preprocessed).filter(
      (w) => w.length >= opts.minLength,
    );
    const sorted = [...matched].sort((a, b) => {
      if (opts.sort === "dict") return 0;
      return opts.sort === "longest" ? b.length - a.length : a.length - b.length;
    });
    return {
      kind: "single",
      words: sorted.map((w) => ({ word: restoreFinalLettersForDisplay(w), score: scoreWord(w) })),
    };
  }, [preprocessed, dict.status, rack, sanitizedRack, sanitizedFixed, opts]);

  function set<K extends keyof Options>(k: K, v: Options[K]) {
    setOpts((prev) => ({ ...prev, [k]: v }));
  }

  const dictReady = dict.status === "ready";

  return (
    <div className="yuval-app">

      {/* Dedication */}
      <header className="dedication">
        <div className="dedication__ornament">❦</div>
        <h1 className="dedication__to">לכבוד</h1>
        <h2 className="dedication__name">יובל כפיר</h2>
        <p className="dedication__body">
          האח הטוב ביותר שיכולתי לאחל לעצמי
        </p>
        <div className="dedication__ornament dedication__ornament--bottom">❦</div>
      </header>

      <div className="divider">
        <span className="divider__line" />
        <span className="divider__text">מחולל האנגרמות</span>
        <span className="divider__line" />
      </div>

      <main className="yuval-search">

        {/* Mode tabs */}
        <div className="mode-tabs" role="tablist">
          {(["multi", "single", "crossword"] as Mode[]).map((m) => (
            <button
              key={m}
              role="tab"
              aria-selected={opts.mode === m}
              className={`mode-tab${opts.mode === m ? " mode-tab--active" : ""}`}
              onClick={() => set("mode", m)}
              disabled={!dictReady}
            >
              {m === "multi" ? "מרובת מילים" : m === "single" ? "מילה בודדת" : "תשבץ"}
            </button>
          ))}
        </div>

        {/* Rack input */}
        <div className="yuval-input-row">
          <input
            className="yuval-input"
            type="text"
            inputMode="text"
            placeholder={
              opts.mode === "crossword"
                ? "תבנית, למשל: ??גד?"
                : "הקלידו אותיות בעברית…"
            }
            value={rack}
            onChange={(e) => setRack(e.target.value)}
            aria-label="אותיות לחיפוש"
            disabled={!dictReady}
            dir="rtl"
          />
          {rack && (
            <button className="yuval-clear" onClick={() => { setRack(""); setFixedWord(""); }} aria-label="נקה">
              ✕
            </button>
          )}
        </div>

        {/* Fixed word (multi only) */}
        {opts.mode === "multi" && (
          <div className={`fixed-row${!fixedWordValid ? " fixed-row--invalid" : ""}`}>
            <label className="fixed-row__label" htmlFor="fixed-word">מילה קבועה</label>
            <input
              id="fixed-word"
              className="yuval-input yuval-input--sm"
              type="text"
              inputMode="text"
              placeholder="תופיע בכל צירוף (לא חובה)"
              value={fixedWord}
              onChange={(e) => setFixedWord(e.target.value)}
              disabled={!dictReady}
              aria-invalid={!fixedWordValid}
              dir="rtl"
            />
            {!fixedWordValid && (
              <p className="fixed-row__error">המילה הקבועה אינה מורכבת מהאותיות שהוזנו</p>
            )}
          </div>
        )}

        {/* Options grid */}
        <div className="yuval-opts">
          {/* minLength — all modes */}
          <label className="opt-label">
            אורך מינימלי למילה
            <select
              className="opt-select"
              value={opts.minLength}
              onChange={(e) => set("minLength", Number(e.target.value))}
              disabled={!dictReady}
            >
              {[2, 3, 4, 5, 6].map((n) => (
                <option key={n} value={n}>{n} אותיות ומעלה</option>
              ))}
            </select>
          </label>

          {/* maxWords — multi only */}
          {opts.mode === "multi" && (
            <label className="opt-label">
              מספר מילים מקסימלי
              <select
                className="opt-select"
                value={opts.maxWords}
                onChange={(e) => set("maxWords", Number(e.target.value))}
                disabled={!dictReady}
              >
                {[2, 3].map((n) => (
                  <option key={n} value={n}>עד {n} מילים</option>
                ))}
              </select>
            </label>
          )}

          {/* sort — single only */}
          {opts.mode === "single" && (
            <label className="opt-label">
              מיון
              <select
                className="opt-select"
                value={opts.sort}
                onChange={(e) => set("sort", e.target.value as SortOrder)}
                disabled={!dictReady}
              >
                <option value="longest">ארוכות ראשון</option>
                <option value="shortest">קצרות ראשון</option>
                <option value="dict">לפי מילון</option>
              </select>
            </label>
          )}

          {/* normalizeFinals */}
          <label className="opt-label opt-label--toggle">
            <input
              type="checkbox"
              checked={opts.normalizeFinals}
              onChange={(e) => set("normalizeFinals", e.target.checked)}
              disabled={!dictReady}
            />
            נרמל אותיות סופיות
          </label>
        </div>

        {/* Results */}
        <ResultsArea result={result} />
      </main>

      <footer className="yuval-footer">
        <a href="../" className="yuval-footer__back">← לאפליקציה הראשית</a>
      </footer>
    </div>
  );
}

// ── Results area ──────────────────────────────────────────────────────────

function ResultsArea({ result }: { result: ReturnType<() => {
  kind: string;
  words?: { word: string; score: number }[];
  combos?: MultiWordResult[];
}> }) {
  if (result.kind === "loading") return <p className="yuval-status">טוען מילון…</p>;
  if (result.kind === "error") return <p className="yuval-status yuval-status--error">טעינת המילון נכשלה</p>;
  if (result.kind === "empty") return null;
  if (result.kind === "fixed-invalid") return null;
  if (result.kind === "too-long") {
    return (
      <p className="yuval-status">
        קלט ארוך מדי — עד {MULTI_WORD_DEFAULT_MAX_INPUT_LETTERS} אותיות
      </p>
    );
  }

  if (result.kind === "multi") {
    const combos = result.combos ?? [];
    if (!combos.length) return <p className="yuval-status">לא נמצאו צירופים</p>;
    const capped = combos.length >= MULTI_WORD_DEFAULT_MAX_RESULTS;
    return (
      <div className="yuval-results">
        <p className="yuval-results__count">
          {combos.length.toLocaleString("he-IL")} צירופים
          {capped ? " (הוגבל)" : ""}
        </p>
        <ul className="yuval-results__list">
          {combos.map((combo, i) => (
            <li key={i} className="yuval-results__item">
              {combo.words.map((w) => restoreFinalLettersForDisplay(w)).join(" · ")}
            </li>
          ))}
        </ul>
      </div>
    );
  }

  // single / crossword
  const words = result.words ?? [];
  if (!words.length) return <p className="yuval-status">לא נמצאו תוצאות</p>;
  return (
    <div className="yuval-results">
      <p className="yuval-results__count">{words.length.toLocaleString("he-IL")} מילים</p>
      <ul className="yuval-results__list">
        {words.map(({ word, score }, i) => (
          <li key={i} className="yuval-results__item yuval-results__item--single">
            <span>{word}</span>
            <span className="yuval-results__score">{score}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}
